import { createTask, getTasks, moveTaskUp } from "wasp/client/operations";
import "./Main.css";

export function MainPage() {
  const [description, setDescription] = useState("");
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskAction = useAction(createTask);
  const moveTaskUpAction = useAction(moveTaskUp, {
    optimisticUpdates: [
      {
        query: getTasks,
        updateQuery: (args, oldData) => {
          if (!oldData) {
            return oldData;
          }

          const taskIndex = oldData.findIndex(
            (task) => task.id === args.taskId
          );

          if (taskIndex <= 0) {
            return oldData;
          }

          const updatedTasks = [...oldData];
          const currentTask = updatedTasks[taskIndex];
          const aboveTask = updatedTasks[taskIndex - 1];

          updatedTasks[taskIndex - 1] = {
            ...currentTask,
            position: aboveTask.position,
          };
          updatedTasks[taskIndex] = {
            ...aboveTask,
            position: currentTask.position,
          };

          return updatedTasks;
        },
      },
    ],
  });

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    const trimmedDescription = description.trim();
    if (!trimmedDescription) {
      return;
    }

    await createTaskAction({ description: trimmedDescription });
    setDescription("");
  };

  if (isLoading) {
    return <

