input.searchContent:
const moveTaskUpAction = useAction(moveTaskUp, {
  optimisticUpdates: [
    {
      query: getTasks,
      updateQuery: (args, oldData) => {
        if (!oldData) {
          return oldData;
        }

        const taskIndex = oldData.findIndex(
          (task) => task.id === args.taskId
        );

        if (taskIndex <= 0) {
          return oldData;
        }

        const updatedTasks = [...oldData];
        const currentTask = updatedTasks[taskIndex];
        const aboveTask = updatedTasks[taskIndex - 1];

        updatedTasks[taskIndex - 1] = {
          ...currentTask,
          position: aboveTask.position,
        };
        updatedTasks[taskIndex] = {
          ...aboveTask,
          position: currentTask.position,
        };

        return updatedTasks;
      },
    },
  ],
});

